CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name varchar(100) UNIQUE NOT NULL, description text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE roles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name varchar(50) UNIQUE NOT NULL, description text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE role_permissions (role_id uuid REFERENCES roles ON DELETE CASCADE, permission_id uuid REFERENCES permissions ON DELETE CASCADE, PRIMARY KEY(role_id,permission_id));
CREATE TABLE users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email varchar(255) UNIQUE NOT NULL, password_hash varchar(255) NOT NULL, name varchar(150) NOT NULL, is_active boolean NOT NULL DEFAULT true, failed_login_count int NOT NULL DEFAULT 0, locked_until timestamptz, last_login_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE user_roles (user_id uuid REFERENCES users ON DELETE CASCADE, role_id uuid REFERENCES roles ON DELETE CASCADE, created_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(user_id,role_id));
CREATE TABLE user_sessions (id uuid PRIMARY KEY, user_id uuid NOT NULL REFERENCES users ON DELETE CASCADE, token_hash char(64) UNIQUE NOT NULL, csrf_hash char(64) NOT NULL, expires_at timestamptz NOT NULL, revoked_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX user_sessions_token_idx ON user_sessions(token_hash) WHERE revoked_at IS NULL;
CREATE TABLE media_files (id uuid PRIMARY KEY, file_name varchar(255) UNIQUE NOT NULL, original_name varchar(255) NOT NULL, mime_type varchar(100) NOT NULL, file_size bigint NOT NULL, url varchar(500) NOT NULL, alt_text varchar(255), caption text, width integer NOT NULL, height integer NOT NULL, created_by uuid NOT NULL REFERENCES users, created_at timestamptz NOT NULL DEFAULT now(), deleted_at timestamptz);
CREATE TABLE categories (id uuid PRIMARY KEY, name varchar(150) NOT NULL, slug varchar(150) NOT NULL, type varchar(20) NOT NULL CHECK(type IN ('news','team')), description text, full_content text, display_order integer NOT NULL DEFAULT 1 CHECK(display_order>0), is_active boolean NOT NULL DEFAULT true, meta_title varchar(255), meta_description varchar(500), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(type,slug));
CREATE TABLE category_translations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), category_id uuid NOT NULL REFERENCES categories ON DELETE CASCADE, locale varchar(10) NOT NULL, name varchar(150) NOT NULL, slug varchar(150) NOT NULL, description text, UNIQUE(category_id,locale));
CREATE TABLE tags (id uuid PRIMARY KEY, name varchar(100) UNIQUE NOT NULL, slug varchar(100) UNIQUE NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TYPE news_status AS ENUM ('draft','in_review','scheduled','published','archived');
CREATE TABLE news (id uuid PRIMARY KEY, title varchar(255) NOT NULL, slug varchar(255) UNIQUE NOT NULL, excerpt text, content text, featured_image_id uuid REFERENCES media_files, category_id uuid REFERENCES categories, status news_status NOT NULL DEFAULT 'draft', is_featured boolean NOT NULL DEFAULT false, published_at timestamptz, scheduled_at timestamptz, created_by uuid NOT NULL REFERENCES users, meta_title varchar(255), meta_description varchar(500), canonical_url varchar(500), legacy_id varchar(255), legacy_path varchar(500), view_count bigint NOT NULL DEFAULT 0, version integer NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), deleted_at timestamptz);
CREATE TABLE news_translations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), news_id uuid NOT NULL REFERENCES news ON DELETE CASCADE, locale varchar(10) NOT NULL, title varchar(255) NOT NULL, slug varchar(255) NOT NULL, excerpt text, content text, UNIQUE(news_id,locale));
CREATE INDEX news_public_idx ON news(status,published_at DESC) WHERE deleted_at IS NULL; CREATE INDEX news_category_idx ON news(category_id);
CREATE TABLE news_tags (news_id uuid REFERENCES news ON DELETE CASCADE, tag_id uuid REFERENCES tags ON DELETE CASCADE, PRIMARY KEY(news_id,tag_id));
CREATE TYPE team_status AS ENUM ('draft','active','inactive','archived');
CREATE TABLE team_members (id uuid PRIMARY KEY, name varchar(255) NOT NULL, slug varchar(255) UNIQUE NOT NULL, academic_titles varchar(255), position varchar(255), short_bio text, bio text, photo_id uuid REFERENCES media_files, email varchar(255), linkedin_url varchar(500), display_order integer NOT NULL DEFAULT 1 CHECK(display_order>0), is_featured boolean NOT NULL DEFAULT false, status team_status NOT NULL DEFAULT 'draft', meta_title varchar(255), meta_description varchar(500), legacy_id varchar(255), legacy_path varchar(500), version integer NOT NULL DEFAULT 1, created_by uuid NOT NULL REFERENCES users, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), deleted_at timestamptz);
CREATE TABLE team_translations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_member_id uuid NOT NULL REFERENCES team_members ON DELETE CASCADE, locale varchar(10) NOT NULL, name varchar(255) NOT NULL, position varchar(255), bio text, UNIQUE(team_member_id,locale));
CREATE INDEX team_public_idx ON team_members(status,display_order) WHERE deleted_at IS NULL;
CREATE TABLE team_member_categories (team_member_id uuid REFERENCES team_members ON DELETE CASCADE, category_id uuid REFERENCES categories ON DELETE RESTRICT, PRIMARY KEY(team_member_id,category_id));
CREATE TABLE redirects (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), source_path varchar(500) NOT NULL, destination_path varchar(500) NOT NULL, status_code integer NOT NULL DEFAULT 301 CHECK(status_code IN(301,302,307,308)), is_active boolean NOT NULL DEFAULT true, created_by uuid REFERENCES users, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE UNIQUE INDEX redirects_active_source_idx ON redirects(source_path) WHERE is_active;
CREATE TABLE audit_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_id uuid, actor_type varchar(20) NOT NULL, action varchar(100) NOT NULL, entity_type varchar(100), entity_id varchar(255), request_id varchar(100), ip_address inet, user_agent text, previous_values jsonb, new_values jsonb, created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX audit_logs_created_idx ON audit_logs(created_at DESC);
CREATE TABLE api_clients (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), client_id varchar(100) UNIQUE NOT NULL, key_id varchar(100) UNIQUE NOT NULL, secret_ciphertext bytea NOT NULL, status varchar(20) NOT NULL DEFAULT 'active', allowed_permissions text[] NOT NULL DEFAULT '{}', expires_at timestamptz, last_used_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE request_nonces (key_id varchar(100) NOT NULL, nonce varchar(100) NOT NULL, expires_at timestamptz NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(key_id,nonce)); CREATE INDEX request_nonces_expiry_idx ON request_nonces(expires_at);
